    Création d'un objet Memcached


<?php
/* Création d'un objet classique */
$m = new Memcached();
echo get_class($m);

/* Création d'un objet persistant */
$m2 = new Memcached('story_pool');
$m3 = new Memcached('story_pool');

/* maintenant $m2 et $m3 partagent la même connexion */
